# Python 3.11+
"""The leaderboard orchestrator. Owns the DUAL INDEX that makes both score reads
and rank reads fast:

  _scores : dict[player_id -> score]              -> O(1) "what's my score"
  _sorted : ascending list of (-score, player_id) -> O(log n) "what's my rank"

We key on NEGATED score so the list is ascending (bisect needs that) while rank 1
is the FIRST element = highest score; ties break by player_id ascending (smaller
id ranks higher). A score change must update BOTH structures together, or a reader
could see a score that disagrees with the ranking вЂ” that compound update is the
critical section.

CLEAN, single-threaded-correct core: the `_read_lock` / `_write_lock` hooks do
nothing here. The thread-safe subclass overrides them with a real read-write lock
so many readers run in parallel while a writer has exclusive access.
"""

import threading
from bisect import bisect_left, insort
from collections.abc import Iterator
from contextlib import contextmanager

from models import (
    InvalidRankError,
    InvalidScoreError,
    Player,
    RankedPlayer,
    UnknownPlayerError,
)


class Leaderboard:
    def __init__(self) -> None:
        self._players: dict[str, Player] = {}
        self._scores: dict[str, int] = {}                  # player_id -> score  (O(1) read)
        # Ascending list of (-score, player_id). Rank 1 = FIRST element (highest
        # score); ties broken by player_id ascending. Negating score lets bisect
        # (which needs ascending) give us a descending leaderboard.
        self._sorted: list[tuple[int, str]] = []

    @staticmethod
    def _key(score: int, player_id: str) -> tuple[int, str]:
        return (-score, player_id)

    # в”Ђв”Ђ concurrency hooks (Template Method) в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
    @contextmanager
    def _read_lock(self) -> Iterator[None]:
        yield                                              # no-op in the clean core

    @contextmanager
    def _write_lock(self) -> Iterator[None]:
        yield                                              # no-op in the clean core

    # в”Ђв”Ђ writes в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
    def add_player(self, player: Player) -> None:
        with self._write_lock():
            if player.id in self._players:
                return                                     # idempotent registration
            self._players[player.id] = player
            self._scores[player.id] = 0
            insort(self._sorted, self._key(0, player.id))

    def submit_score(self, player_id: str, delta: int) -> int:
        """Adjust a player's score by `delta` and return the new total."""
        if delta == 0:
            raise InvalidScoreError("delta must be non-zero")
        with self._write_lock():
            if player_id not in self._players:
                raise UnknownPlayerError(player_id)
            old = self._scores[player_id]
            new = old + delta
            # COMPOUND UPDATE вЂ” both structures move together, atomically under the
            # write lock, so no reader ever sees the dict and the index disagree.
            self._sorted.pop(bisect_left(self._sorted, self._key(old, player_id)))
            insort(self._sorted, self._key(new, player_id))
            self._scores[player_id] = new
            return new

    # в”Ђв”Ђ reads в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
    def get_score(self, player_id: str) -> int:
        with self._read_lock():
            if player_id not in self._players:
                raise UnknownPlayerError(player_id)
            return self._scores[player_id]

    def get_rank(self, player_id: str) -> int:
        """1-based rank: rank 1 is the highest score."""
        with self._read_lock():
            if player_id not in self._players:
                raise UnknownPlayerError(player_id)
            key = self._key(self._scores[player_id], player_id)
            # players strictly ABOVE this key occupy [0, bisect_left); rank = that + 1
            return bisect_left(self._sorted, key) + 1

    def top_k(self, k: int) -> list[RankedPlayer]:
        if k <= 0:
            raise InvalidRankError("k must be positive")
        with self._read_lock():
            return [
                RankedPlayer(player_id=pid, score=-neg_score, rank=i + 1)
                for i, (neg_score, pid) in enumerate(self._sorted[:k])
            ]

    def size(self) -> int:
        with self._read_lock():
            return len(self._players)


class ReadWriteLock:
    """A reader-preference read-write lock: any number of readers concurrently,
    but a writer gets exclusive access. (Reader-preference can starve writers under
    a constant read stream вЂ” see В§9; a fair/writer-preference variant fixes that.)
    """

    def __init__(self) -> None:
        self._readers = 0
        self._cond = threading.Condition(threading.Lock())

    @contextmanager
    def read(self) -> Iterator[None]:
        with self._cond:
            self._readers += 1
        try:
            yield
        finally:
            with self._cond:
                self._readers -= 1
                if self._readers == 0:
                    self._cond.notify_all()                # wake a waiting writer

    @contextmanager
    def write(self) -> Iterator[None]:
        self._cond.acquire()
        try:
            while self._readers > 0:                       # wait for readers to drain
                self._cond.wait()
            yield
        finally:
            self._cond.release()


class ThreadSafeLeaderboard(Leaderboard):
    """Same logic; the only change is real locking via a read-write lock, so
    `get_rank`/`top_k`/`get_score` run in parallel while `submit_score` is exclusive.
    """

    def __init__(self) -> None:
        super().__init__()
        self._rwlock = ReadWriteLock()

    @contextmanager
    def _read_lock(self) -> Iterator[None]:
        with self._rwlock.read():
            yield

    @contextmanager
    def _write_lock(self) -> Iterator[None]:
        with self._rwlock.write():
            yield
